import{_ as t,o as a,c as r,a2 as s}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Gestion des mails","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/mail-management.md","filePath":"fr/guide/mail-management.md"}'),o={name:"fr/guide/mail-management.md"};function l(n,e,i,d,c,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="gestion-des-mails" tabindex="-1">Gestion des mails <a class="header-anchor" href="#gestion-des-mails" aria-label="Permalink to &quot;Gestion des mails&quot;">​</a></h1><p>La page <strong>Mes mails</strong> est le cœur de Nid. Elle vous permet de consulter, filtrer et agir en masse sur les mails de votre boîte Gmail.</p><hr><h2 id="consultation-des-mails" tabindex="-1">Consultation des mails <a class="header-anchor" href="#consultation-des-mails" aria-label="Permalink to &quot;Consultation des mails&quot;">​</a></h2><p>La page affiche la liste de vos mails Gmail avec les informations essentielles : expéditeur, objet, date, taille, labels et indicateur de pièces jointes.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : page Mes mails avec la liste des mails, les filtres et la barre d&#39;actions</em></p></blockquote><h3 id="recherche" tabindex="-1">Recherche <a class="header-anchor" href="#recherche" aria-label="Permalink to &quot;Recherche&quot;">​</a></h3><p>Utilisez la barre de recherche en haut de la page. Elle supporte la <strong>syntaxe native Gmail</strong> :</p><table tabindex="0"><thead><tr><th>Exemple</th><th>Description</th></tr></thead><tbody><tr><td><code>from:amazon.fr</code></td><td>Mails de Amazon</td></tr><tr><td><code>subject:facture</code></td><td>Mails contenant &quot;facture&quot; dans l&#39;objet</td></tr><tr><td><code>has:attachment larger:5M</code></td><td>Mails avec PJ de plus de 5 Mo</td></tr><tr><td><code>older_than:1y</code></td><td>Mails de plus d&#39;un an</td></tr><tr><td><code>is:unread from:newsletter</code></td><td>Newsletters non lues</td></tr><tr><td><code>label:promotions</code></td><td>Mails dans le label Promotions</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : barre de recherche Gmail avec suggestions</em></p></blockquote><h3 id="lecture-d-un-mail" tabindex="-1">Lecture d&#39;un mail <a class="header-anchor" href="#lecture-d-un-mail" aria-label="Permalink to &quot;Lecture d&#39;un mail&quot;">​</a></h3><p>Cliquez sur un mail pour l&#39;ouvrir dans le <strong>lecteur intégré</strong>. Le lecteur affiche :</p><ul><li>Le corps du mail (HTML ou texte brut)</li><li>Les pièces jointes avec possibilité de téléchargement</li><li>Les métadonnées (expéditeur, destinataires, date, taille)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : lecteur de mail ouvert avec un mail HTML et des pièces jointes</em></p></blockquote><hr><h2 id="actions-en-masse-bulk" tabindex="-1">Actions en masse (bulk) <a class="header-anchor" href="#actions-en-masse-bulk" aria-label="Permalink to &quot;Actions en masse (bulk)&quot;">​</a></h2><p>Sélectionnez un ou plusieurs mails (cases à cocher) pour faire apparaître la <strong>barre d&#39;actions en masse</strong> :</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Supprimer (corbeille)</strong></td><td>Envoie les mails à la corbeille Gmail (récupérables 30 jours)</td></tr><tr><td><strong>Supprimer définitivement</strong></td><td>Suppression irréversible des mails</td></tr><tr><td><strong>Archiver Gmail</strong></td><td>Retire les mails de la boîte de réception (label INBOX)</td></tr><tr><td><strong>Marquer comme lu</strong></td><td>Marque tous les mails sélectionnés comme lus</td></tr><tr><td><strong>Marquer comme non lu</strong></td><td>Marque tous les mails sélectionnés comme non lus</td></tr><tr><td><strong>Ajouter un label</strong></td><td>Applique un label Gmail aux mails sélectionnés</td></tr><tr><td><strong>Archiver sur NAS</strong></td><td>Sauvegarde les mails en EML sur votre NAS</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : barre d&#39;actions en masse avec mails sélectionnés</em></p></blockquote><h3 id="tout-selectionner" tabindex="-1">Tout sélectionner <a class="header-anchor" href="#tout-selectionner" aria-label="Permalink to &quot;Tout sélectionner&quot;">​</a></h3><p>Cochez la case dans l&#39;en-tête du tableau pour sélectionner tous les mails de la page courante.</p><h3 id="archiver-tous-les-resultats" tabindex="-1">Archiver tous les résultats <a class="header-anchor" href="#archiver-tous-les-resultats" aria-label="Permalink to &quot;Archiver tous les résultats&quot;">​</a></h3><p>Le bouton <strong>Tout archiver</strong> lance un archivage différentiel de <strong>tous</strong> les mails correspondant à la recherche en cours, sans sélection manuelle. C&#39;est un job asynchrone avec suivi en temps réel.</p><hr><h2 id="operations-asynchrones" tabindex="-1">Opérations asynchrones <a class="header-anchor" href="#operations-asynchrones" aria-label="Permalink to &quot;Opérations asynchrones&quot;">​</a></h2><p>Les opérations en masse sont exécutées en arrière-plan via des <strong>jobs</strong>. Quand vous lancez une opération :</p><ol><li>Un job est créé immédiatement</li><li>Une <strong>modale de progression</strong> s&#39;affiche avec une barre de progression en temps réel</li><li>Vous pouvez fermer la modale — le job continue en arrière-plan</li><li>Consultez la page <strong>Jobs</strong> pour suivre tous vos jobs en cours</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : modale JobProgressModal avec barre de progression à 60%</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Annulation</p><p>Vous pouvez annuler un job en cours depuis la page <strong>Jobs</strong>. Les mails déjà traités ne sont pas annulés.</p></div><hr><h2 id="raccourcis-clavier" tabindex="-1">Raccourcis clavier <a class="header-anchor" href="#raccourcis-clavier" aria-label="Permalink to &quot;Raccourcis clavier&quot;">​</a></h2><p>La page Mes mails supporte des raccourcis clavier pour une navigation rapide :</p><table tabindex="0"><thead><tr><th>Touche</th><th>Action</th></tr></thead><tbody><tr><td><kbd>j</kbd></td><td>Mail suivant</td></tr><tr><td><kbd>k</kbd></td><td>Mail précédent</td></tr><tr><td><kbd>enter</kbd> / <kbd>o</kbd></td><td>Ouvrir le mail sélectionné</td></tr><tr><td><kbd>e</kbd></td><td>Archiver (Gmail)</td></tr><tr><td><kbd>&quot;#&quot;</kbd></td><td>Supprimer (corbeille)</td></tr><tr><td><kbd>r</kbd></td><td>Marquer comme lu</td></tr><tr><td><kbd>u</kbd></td><td>Marquer comme non lu</td></tr><tr><td><kbd>&quot;/&quot;</kbd></td><td>Focus sur la barre de recherche</td></tr><tr><td><kbd>escape</kbd></td><td>Désélectionner</td></tr></tbody></table><p>Les raccourcis sont automatiquement désactivés quand vous tapez dans un champ de saisie.</p><blockquote><p>📸 <em>Capture d&#39;écran suggérée : bandeau de raccourcis clavier en bas de la page Mes mails</em></p></blockquote>',35)])])}const h=t(o,[["render",l]]);export{p as __pageData,h as default};
